def longest_run_char(s):
    max_length, max_char = 0, ''
    current_char, current_length = None, 0
    for char in s:
        if char == current_char:
            current_length += 1
        else:
            if current_length > max_length:
                max_length, max_char = current_length, current_char
            current_char, current_length = char, 1
    # Handling edge case when the last character has the longest run
